import random
import time
from dataclasses import dataclass

GPU_MEM_SIZE = 80  # GB

@dataclass
class Model:
    model_name: str
    model_size: int   # GB
    req_rate: int     # requests per second
    slo: int          # service level objective (latency target)
    cur_gpu_id: int   # current GPU assignment (can be ignored)

def compute_model_placement(gpu_num: int, models: list[Model]) -> dict[int, list[Model]]:
    """
    Optimizes model placement to minimize maximum KVPR using a Greedy + Local Search approach.
    KVPR = sum(r/s) / (80 - sum(size))
    """
    start_time = time.time()

    def get_kvpr(gpu_models):
        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        total_weighted_rate = sum(m.req_rate / m.slo for m in gpu_models)
        return total_weighted_rate / (GPU_MEM_SIZE - total_size)

    # 1. Initial Placement: Best Fit Decreasing (by size) to ensure feasibility
    # Then refine using a greedy approach for KVPR
    sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)

    current_placement = {i: [] for i in range(gpu_num)}

    for model in sorted_models:
        best_gpu = -1
        min_kvpr_after = float('inf')

        # Try to place in the GPU that results in the lowest KVPR for that specific GPU
        for gpu_id in range(gpu_num):
            temp_list = current_placement[gpu_id] + [model]
            size_sum = sum(m.model_size for m in temp_list)
            if size_sum < GPU_MEM_SIZE:
                kvpr = get_kvpr(temp_list)
                if kvpr < min_kvpr_after:
                    min_kvpr_after = kvpr
                    best_gpu = gpu_id

        if best_gpu != -1:
            current_placement[best_gpu].append(model)
        else:
            # Emergency fallback: find any GPU that fits
            for gpu_id in range(gpu_num):
                if sum(m.model_size for m in current_placement[gpu_id]) + model.model_size < GPU_MEM_SIZE:
                    current_placement[gpu_id].append(model)
                    break

    # 2. Local Search: Iterative Improvement (Hill Climbing)
    # Target the GPU with the maximum KVPR and try to move or swap models
    timeout = 8.0 # seconds (leaving buffer for 10s limit)

    while time.time() - start_time < timeout:
        improved = False

        # Calculate current KVPRs
        gpu_kvprs = {i: get_kvpr(current_placement[i]) for i in range(gpu_num)}
        max_gpu = max(gpu_kvprs, key=gpu_kvprs.get)
        max_val = gpu_kvprs[max_gpu]

        # Try moving a model from the bottleneck GPU to another GPU
        for model_idx, model in enumerate(current_placement[max_gpu]):
            for target_gpu in range(gpu_num):
                if target_gpu == max_gpu:
                    continue

                # Check if move is feasible
                new_target_size = sum(m.model_size for m in current_placement[target_gpu]) + model.model_size
                if new_target_size < GPU_MEM_SIZE:
                    # Calculate potential new max KVPR
                    new_max_gpu_kvpr = get_kvpr([m for i, m in enumerate(current_placement[max_gpu]) if i != model_idx])
                    new_target_gpu_kvpr = get_kvpr(current_placement[target_gpu] + [model])

                    potential_max = max(new_max_gpu_kvpr, new_target_gpu_kvpr)
                    # Also check other GPUs' KVPRs
                    for other_gpu, other_kvpr in gpu_kvprs.items():
                        if other_gpu != max_gpu and other_gpu != target_gpu:
                            potential_max = max(potential_max, other_kvpr)

                    if potential_max < max_val - 1e-9:
                        # Apply move
                        m = current_placement[max_gpu].pop(model_idx)
                        current_placement[target_gpu].append(m)
                        improved = True
                        break
            if improved: break

        if not improved:
            # Try swapping a model from max_gpu with a model from another gpu
            for m_idx, m_max in enumerate(current_placement[max_gpu]):
                for other_gpu in range(gpu_num):
                    if other_gpu == max_gpu: continue
                    for o_idx, m_other in enumerate(current_placement[other_gpu]):

                        # Feasibility check
                        size_max_after = sum(m.model_size for m in current_placement[max_gpu]) - m_max.model_size + m_other.model_size
                        size_other_after = sum(m.model_size for m in current_placement[other_gpu]) - m_other.model_size + m_max.model_size

                        if size_max_after < GPU_MEM_SIZE and size_other_after < GPU_MEM_SIZE:
                            new_list_max = [m for i, m in enumerate(current_placement[max_gpu]) if i != m_idx] + [m_other]
                            new_list_other = [m for i, m in enumerate(current_placement[other_gpu]) if i != o_idx] + [m_max]

                            p_max = max(get_kvpr(new_list_max), get_kvpr(new_list_other))
                            for g_id, kv in gpu_kvprs.items():
                                if g_id != max_gpu and g_id != other_gpu:
                                    p_max = max(p_max, kv)

                            if p_max < max_val - 1e-9:
                                current_placement[max_gpu][m_idx] = m_other
                                current_placement[other_gpu][o_idx] = m_max
                                improved = True
                                break
                    if improved: break
                if improved: break

        if not improved:
            break # Local optimum reached

    return current_placement
